package neetcode.validAnagram;

import org.junit.Assert;
import org.junit.Test;
import org.junit.runner.RunWith;

import com.tngtech.java.junit.dataprovider.DataProvider;
import com.tngtech.java.junit.dataprovider.DataProviderRunner;
import com.tngtech.java.junit.dataprovider.UseDataProvider;

import ttg.traning.neetcode.validAnagram.ValidAnagram;

/**
 *
 * @author ttg
 */
@RunWith(DataProviderRunner.class)
public class ValidAnagramTest {

    @DataProvider
    public static Object[][] provideDataForIsAnagram() {
        return new Object[][]{
                // Examples from problem statement
                {"racecar", "carrace", true},
                {"jar", "jam", false},
                {"",
                 "",
                 true},

                // Same multiset, different order
                {"anagram", "nagaram", true},
                {"listen", "silent", true},

                // Same string (identity)
                {"hello", "hello", true},

                // Length mismatch
                {"a", "ab", false},
                {"", "a", false},

                // Same length, different character counts
                {"aa", "ab", false},
                {"ab", "aa", false},

                // Single character
                {"z", "z", true},
                {"a", "b", false},

                // Both empty (same multiset)
                {"", "", true}
        };
    }

    @Test
    @UseDataProvider("provideDataForIsAnagram")
    public void testIsAnagram(String s, String t, boolean expected) {
        ValidAnagram solver = new ValidAnagram();
        boolean actual = solver.isAnagram(s, t);

        Assert.assertEquals(expected, actual);
    }
}
